import{G as a,c as r,b as t,ae as l}from"./chunks/framework.Cpb2nuHT.js";const p=JSON.parse('{"title":"Mac 好用软件整理","description":"","frontmatter":{"title":"Mac 好用软件整理","date":"2025/10/18 11:58","author":"花木凋零成兰","tags":["Mac","APP"],"hiddenCover":true},"headers":[],"relativePath":"Mac环境搭建/Mac好用软件整理.md","filePath":"Mac环境搭建/Mac好用软件整理.md","lastUpdated":1760848027000}'),o={name:"Mac环境搭建/Mac好用软件整理.md"};function i(n,e,h,s,c,d){return t(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1760788680000"},[...e[0]||(e[0]=[l('<h1 id="mac-好用软件整理" tabindex="-1">Mac 好用软件整理 <a class="header-anchor" href="#mac-好用软件整理" aria-label="Permalink to &quot;Mac 好用软件整理&quot;">​</a></h1><blockquote><p>系统版本：macOS Sequoia 15.6</p></blockquote><h2 id="系统相关" tabindex="-1">系统相关 <a class="header-anchor" href="#系统相关" aria-label="Permalink to &quot;系统相关&quot;">​</a></h2><ul><li><a href="https://en.clashx.org/" target="_blank" rel="noreferrer">ClashX Pro</a>：加快网络访问；搭配<a href="https://fbinv02.fbaff.cc/auth/register?code=FOzfxbnz" target="_blank" rel="noreferrer">机场</a></li><li><a href="https://mos.caldis.me/" target="_blank" rel="noreferrer">Mos</a>：优化鼠标滑动体验</li><li><a href="https://github.com/thealpa/SaneSideButtons" target="_blank" rel="noreferrer">SaneSideButtons</a>：优化鼠标侧键</li><li><a href="https://z.weixin.qq.com/" target="_blank" rel="noreferrer">微信输入法</a>：多端剪切板同步，满足基本日常使用</li><li><a href="https://lemon.qq.com/" target="_blank" rel="noreferrer">Tencent Lemon</a>：腾讯柠檬清理，免费的 Mac 垃圾清理工具，缺点是界面风格很 Windows</li><li><a href="https://github.com/MrKai77/Loop" target="_blank" rel="noreferrer">Loop</a>：分屏增强工具，通过 快捷键+鼠标移动 的方式实现快速分屏</li><li>RunCat：系统检测工具，可以实时查看 CPU 和内存压力；在APP Store 安装即可；</li><li>Hidden Bar：顶部 Finder 图标显示管理，在APP Store 安装即可；</li><li><a href="https://keyboardholder.leavesc.com/zh-cn/" target="_blank" rel="noreferrer">KeyboardHolder</a>：灵活自动切换输入法，可以为每个 APP 定制使用的输入法；</li><li><a href="https://www.raycast.com/" target="_blank" rel="noreferrer">Raycast</a>：快速启动器，比自带的 Spotlight 更为强大；<a href="https://juejin.cn/post/7343863800145494079?searchId=20251018125434DA1E6F235F0C45D146D3" target="_blank" rel="noreferrer">参考文章</a></li><li><a href="https://alt-tab-macos.netlify.app/" target="_blank" rel="noreferrer">AltTab</a>：窗口切换增加，使用快捷键<code>opt+tab</code>切换窗口时，可以像 Windows 一样看到软件内容窗口，并且可以直接在切换界面对软件进行关闭；</li><li><a href="https://zh.snipaste.com/" target="_blank" rel="noreferrer">Snipaste</a>：截屏、贴图工具；</li><li><a href="https://www.mowglii.com/itsycal/" target="_blank" rel="noreferrer">Itsycal</a>：免费的日历小工具</li><li><a href="https://brew.sh/" target="_blank" rel="noreferrer">Homebrew</a>：无法避开的 Mac 软件安装命令工具，<a href="https://blog.csdn.net/weixin_38716347/article/details/123838344" target="_blank" rel="noreferrer">参考文章</a>；结合<a href="./WezTerm+Starship美化Mac终端.html">终端美化</a></li></ul><h2 id="好用软件" tabindex="-1">好用软件 <a class="header-anchor" href="#好用软件" aria-label="Permalink to &quot;好用软件&quot;">​</a></h2><h3 id="开发及笔记" tabindex="-1">开发及笔记 <a class="header-anchor" href="#开发及笔记" aria-label="Permalink to &quot;开发及笔记&quot;">​</a></h3><ul><li><a href="https://miaoyan.app/?from=thosefree.com" target="_blank" rel="noreferrer">妙言</a>：支持在 iCloud 同步，非常好看强大的 Markdown 编辑器；适合作为主用的笔记软件;</li><li><a href="https://www.jetbrains.com/toolbox-app/" target="_blank" rel="noreferrer">JetBrains 全家桶</a>：毋庸置疑的开发工具；</li><li><a href="https://termius.com/" target="_blank" rel="noreferrer">termius</a>：好用的 SSH 工具；</li><li><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VS Code</a>：强大的编辑器；<a href="https://blog.csdn.net/weixin_42881768/article/details/119635248" target="_blank" rel="noreferrer">如何在终端安装 Code 命令</a>；</li><li>CotEditor：轻量级文本编辑器，在 APP Store 获取；安装后不需要配置就很好用，在终端运行命令<code>sudo ln -s /Applications/CotEditor.app/Contents/SharedSupport/bin/cot /usr/local/bin/cot</code>；即可在终端通过<code>cot</code>打开文件进行编辑；</li></ul><h3 id="网盘及下载" tabindex="-1">网盘及下载 <a class="header-anchor" href="#网盘及下载" aria-label="Permalink to &quot;网盘及下载&quot;">​</a></h3><ul><li><a href="https://pan.quark.cn/list#/list/all" target="_blank" rel="noreferrer">夸克网盘</a></li><li><a href="https://pan.baidu.com/disk/main?from=oldversion#/index" target="_blank" rel="noreferrer">百度网盘</a></li><li><a href="https://www.aliyundrive.com/download" target="_blank" rel="noreferrer">阿里云盘</a></li><li><a href="https://motrix.app/zh-CN/" target="_blank" rel="noreferrer">Motrix</a>：磁力链接下载工具</li></ul><h2 id="软件网站-仅学习使用" tabindex="-1">软件网站(仅学习使用) <a class="header-anchor" href="#软件网站-仅学习使用" aria-label="Permalink to &quot;软件网站(仅学习使用)&quot;">​</a></h2><ul><li><a href="https://www.macbl.com/" target="_blank" rel="noreferrer">马克波罗</a></li><li><a href="https://macwk.cn/" target="_blank" rel="noreferrer">macWk</a></li></ul><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://www.zhihu.com/question/387151850/answer/3391743530" target="_blank" rel="noreferrer">MacBook刚买回来首先需要做那些事?</a></li><li><a href="https://www.bilibili.com/video/BV1aA6HYQE3N/?spm_id_from=333.1391.0.0&amp;vd_source=67085386ad37b864cf255529b5a127f7" target="_blank" rel="noreferrer">【果粉必备】 Mac新手小白入门指南|基本操作|快捷键|软件下载与安装分享</a></li></ul>',13)])])}const b=a(o,[["render",i]]);export{p as __pageData,b as default};
